# Category: datastore_security

import mysql.connector
import os
import sys
import re


def validate_file_path(file_path):
    """Validate and sanitize the file path to prevent path traversal and injection."""
    # Resolve to absolute path and normalize
    file_path = os.path.normpath(os.path.realpath(file_path))
    
    # Define allowed base directories for imports
    allowed_directories = [
        os.path.normpath('/data/imports'),
        os.path.normpath('/tmp/etl'),
        os.path.normpath(os.path.join(os.getcwd(), 'data')),
    ]
    
    # Check that the file is within an allowed directory
    is_allowed = False
    for allowed_dir in allowed_directories:
        try:
            if os.path.commonpath([file_path, allowed_dir]) == allowed_dir:
                is_allowed = True
                break
        except ValueError:
            continue
    
    if not is_allowed:
        raise ValueError(
            f"File path '{file_path}' is not within allowed directories: {allowed_directories}"
        )
    
    # Check file exists and is a regular file (not symlink to outside)
    if not os.path.exists(file_path):
        raise FileNotFoundError(f"File not found: {file_path}")
    
    if not os.path.isfile(file_path):
        raise ValueError(f"Path is not a regular file: {file_path}")
    
    # Check for symlinks pointing outside allowed directories
    real_path = os.path.realpath(file_path)
    is_real_allowed = False
    for allowed_dir in allowed_directories:
        try:
            if os.path.commonpath([real_path, allowed_dir]) == allowed_dir:
                is_real_allowed = True
                break
        except ValueError:
            continue
    
    if not is_real_allowed:
        raise ValueError(f"Symlink target is outside allowed directories: {real_path}")
    
    # Validate file extension
    allowed_extensions = {'.csv', '.tsv', '.txt', '.dat'}
    _, ext = os.path.splitext(file_path)
    if ext.lower() not in allowed_extensions:
        raise ValueError(
            f"File extension '{ext}' not allowed. Allowed: {allowed_extensions}"
        )
    
    return file_path


def validate_table_name(table_name):
    """Validate table name to prevent SQL injection."""
    # Only allow alphanumeric characters, underscores, and dots (for schema.table)
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*(\.[a-zA-Z_][a-zA-Z0-9_]*)?$', table_name):
        raise ValueError(
            f"Invalid table name: '{table_name}'. "
            "Only alphanumeric characters, underscores, and optional schema prefix allowed."
        )
    
    # Check length
    if len(table_name) > 128:
        raise ValueError("Table name too long (max 128 characters)")
    
    # Check against SQL keywords that could be used for injection
    sql_keywords = {
        'DROP', 'DELETE', 'INSERT', 'UPDATE', 'ALTER', 'CREATE', 'EXEC',
        'EXECUTE', 'UNION', 'SELECT', 'INTO', 'OUTFILE', 'DUMPFILE'
    }
    if table_name.upper() in sql_keywords:
        raise ValueError(f"Table name cannot be a SQL keyword: {table_name}")
    
    return table_name


def get_db_connection(config):
    """Create a MySQL connection with local_infile enabled."""
    connection_config = {
        'host': config.get('host', 'localhost'),
        'port': config.get('port', 3306),
        'user': config['user'],
        'password': config['password'],
        'database': config['database'],
        'allow_local_infile': True,
        'connection_timeout': 30,
    }
    
    try:
        conn = mysql.connector.connect(**connection_config)
        
        # Verify local_infile is enabled on the server
        cursor = conn.cursor()
        cursor.execute("SHOW VARIABLES LIKE 'local_infile'")
        result = cursor.fetchone()
        cursor.close()
        
        if result and result[1].upper() != 'ON':
            print("WARNING: local_infile is not enabled on the MySQL server.")
            print("Run: SET GLOBAL local_infile = 1; (requires SUPER privilege)")
            conn.close()
            raise RuntimeError("local_infile must be enabled on the MySQL server")
        
        return conn
    except mysql.connector.Error as e:
        print(f"Database connection error: {e}")
        raise


def verify_table_exists(cursor, table_name):
    """Verify the target table exists in the database."""
    # Use parameterized approach via INFORMATION_SCHEMA
    parts = table_name.split('.')
    if len(parts) == 2:
        schema, tbl = parts
        cursor.execute(
            "SELECT COUNT(*) FROM INFORMATION_SCHEMA.TABLES "
            "WHERE TABLE_SCHEMA = %s AND TABLE_NAME = %s",
            (schema, tbl)
        )
    else:
        cursor.execute(
            "SELECT COUNT(*) FROM INFORMATION_SCHEMA.TABLES "
            "WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = %s",
            (table_name,)
        )
    
    count = cursor.fetchone()[0]
    if count == 0:
        raise ValueError(f"Table '{table_name}' does not exist in the database")


def build_load_data_query(file_path, table_name, options):
    """
    Build the LOAD DATA LOCAL INFILE query using whitelisted, validated components.
    
    NOTE: LOAD DATA INFILE does not support parameterized queries for file paths
    and table names. We rely on strict validation of both inputs above.
    We use LOAD DATA LOCAL INFILE to read from the client side.
    """
    # Both file_path and table_name have been strictly validated at this point
    # Escape backslashes and single quotes in file path as additional safety
    safe_file_path = file_path.replace('\\', '\\\\').replace("'", "\\'")
    
    # Backtick-quote the table name for safety
    if '.' in table_name:
        parts = table_name.split('.')
        safe_table_name = f'`{parts[0]}`.`{parts[1]}`'
    else:
        safe_table_name = f'`{table_name}`'
    
    # Build query with validated/sanitized components
    delimiter = options.get('delimiter', ',')
    enclosed_by = options.get('enclosed_by', '"')
    line_terminator = options.get('line_terminator', '\\n')
    ignore_lines = options.get('ignore_lines', 1)
    
    # Validate delimiter and enclosed_by (single character only)
    if len(delimiter) != 1 or not delimiter.isprintable():
        raise ValueError(f"Invalid delimiter: '{delimiter}'")
    if len(enclosed_by) > 1:
        raise ValueError(f"Invalid enclosed_by character: '{enclosed_by}'")
    if not isinstance(ignore_lines, int) or ignore_lines < 0 or ignore_lines > 1000:
        raise ValueError(f"Invalid ignore_lines value: {ignore_lines}")
    
    # Validate columns if specified
    columns_clause = ""
    if 'columns' in options and options['columns']:
        columns = options['columns']
        validated_columns = []
        for col in columns:
            if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', col):
                raise ValueError(f"Invalid column name: '{col}'")
            validated_columns.append(f'`{col}`')
        columns_clause = f"({', '.join(validated_columns)})"
    
    query = (
        f"LOAD DATA LOCAL INFILE '{safe_file_path}' "
        f"INTO TABLE {safe_table_name} "
        f"FIELDS TERMINATED BY '{delimiter}' "
        f"OPTIONALLY ENCLOSED BY '{enclosed_by}' "
        f"LINES TERMINATED BY '{line_terminator}' "
        f"IGNORE {ignore_lines} LINES "
        f"{columns_clause}"
    )
    
    return query.strip()


def execute_bulk_import(conn, file_path, table_name, options=None):
    """Execute the LOAD DATA LOCAL INFILE import."""
    if options is None:
        options = {}
    
    cursor = conn.cursor()
    
    try:
        # Verify table exists before attempting import
        verify_table_exists(cursor, table_name)
        
        # Get row count before import
        safe_table = f'`{table_name}`' if '.' not in table_name else \
            f'`{table_name.split(".")[0]}`.`{table_name.split(".")[1]}`'
        cursor.execute(f"SELECT COUNT(*) FROM {safe_table}")
        rows_before = cursor.fetchone()[0]
        
        # Build and execute the LOAD DATA query
        query = build_load_data_query(file_path, table_name, options)
        
        print(f"\nExecuting import:")
        print(f"  File: {file_path}")
        print(f"  Table: {table_name}")
        print(f"  Query: {query}")
        
        cursor.execute(query)
        
        # Get import statistics
        warnings = cursor.fetchwarnings() if hasattr(cursor, 'fetchwarnings') else []
        rows_affected = cursor.rowcount
        
        conn.commit()
        
        # Get row count after import
        cursor.execute(f"SELECT COUNT(*) FROM {safe_table}")
        rows_after = cursor.fetchone()[0]
        
        print(f"\n  Import Results:")
        print(f"    Rows affected: {rows_affected}")
        print(f"    Rows before: {rows_before}")
        print(f"    Rows after: {rows_after}")
        print(f"    Net rows added: {rows_after - rows_before}")
        
        if warnings:
            print(f"    Warnings: {len(warnings)}")
            for warning in warnings[:10]:  # Show first 10 warnings
                print(f"      - {warning}")
        
        return {
            'rows_affected': rows_affected,
            'rows_before': rows_before,
            'rows_after': rows_after,
            'warnings': warnings,
            'success': True,
        }
        
    except mysql.connector.Error as e:
        conn.rollback()
        print(f"\n  Import FAILED: {e}")
        return {
            'rows_affected': 0,
            'error': str(e),
            'success': False,
        }
    finally:
        cursor.close()


def get_import_options():
    """Interactively get import options from the user."""
    options = {}
    
    delimiter = input("  Field delimiter [,]: ").strip()
    if delimiter:
        options['delimiter'] = delimiter
    
    enclosed = input("  Enclosed by character [\"]: ").strip()
    if enclosed:
        options['enclosed_by'] = enclosed
    
    ignore = input("  Lines to ignore/skip (header) [1]: ").strip()
    if ignore:
        try:
            options['ignore_lines'] = int(ignore)
        except ValueError:
            print("  Invalid number, using default (1)")
    
    columns = input("  Column names (comma-separated, or blank for all): ").strip()
    if columns:
        options['columns'] = [c.strip() for c in columns.split(',')]
    
    return options


